sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    // 1. Declare an empty array called 'answer'
    var answer = [];

    // 2. Save each of the query parameters in a separate variable
    var make = request.queryParams.make;
    var model = request.queryParams.model;
    var year = request.queryParams.year;
    var country = request.queryParams.country;
    var city = request.queryParams.city;

    // Generate a 404 error if no query parameters are provided
    if (!make && !model && !year && !country && !city) {
        response.setStatus(404);
        response.setBody({
            error: {
                message: 'Query parameters required',
                detail: 'Please provide at least one query parameter: make, model, year, country, or city'
            }
        });
        return;
    }

    // 3. Query the x_snc_vehicle_ma_0_vehicle table using the query parameters
    var vehicleGR = new GlideRecord('x_snc_vehicle_ma_0_vehicle');
    if (make) {
        vehicleGR.addQuery('make', make);
    }
    if (model) {
        vehicleGR.addQuery('model', model);
    }
    if (year) {
        vehicleGR.addQuery('year', year);
    }
    if (country) {
        vehicleGR.addQuery('country', country);
    }
    if (city) {
        vehicleGR.addQuery('city', city);
    }
    vehicleGR.query();

    // 4. Generate a 404 error message if no vehicles were found
    if (!vehicleGR.hasNext()) {
        response.setStatus(404);
        response.setBody({
            error: {
                message: 'No vehicles found',
                detail: 'No vehicles matched the provided search criteria'
            }
        });
        return;
    }

    // 5 & 6. For found vehicles, generate JSON objects and push into 'answer' array
    while (vehicleGR.next()) {
        var vehicleObj = {
            make: vehicleGR.getValue('make'),
            model: vehicleGR.getValue('model'),
            year: vehicleGR.getValue('year'),
            vin: vehicleGR.getValue('vin'),
            country: vehicleGR.getValue('country'),
            city: vehicleGR.getValue('city'),
            start_date: vehicleGR.getValue('start_date'),
            end_date: vehicleGR.getValue('end_date')
        };
        answer.push(vehicleObj);
    }

    // 7. Generate a response body that contains the 'answer' variable
    response.setBody(answer);
})(request, response);
